function b64_to_utf8(str) {
  try {
    // This is a more robust way to decode base64 to UTF-8
    const binaryString = atob(str);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return new TextDecoder().decode(bytes);
  } catch (e) {
    console.error("Failed to decode base64 string:", e);
    return ""; // Return empty string on failure
  }
}

const INSTALLER_SCRIPT = b64_to_utf8(``);
const INSTALLER_SCRIPT_ZH = b64_to_utf8(``);

const README_URL_EN = 'https://github.com/Silentely/fuckits/blob/main/README.en.md';
const README_URL_ZH = 'https://github.com/Silentely/fuckits';
const INSTALLER_FILENAME_EN = 'fuckits.sh';
const INSTALLER_FILENAME_ZH = 'fuckits-zh.sh';
const SHARED_DEFAULT_LIMIT = 10;
const SECONDS_IN_DAY = 24 * 60 * 60;
const CACHE_TTL_SECONDS = 24 * 60 * 60;
const CACHE_STATS_TTL_SECONDS = 2 * 24 * 60 * 60;
const OPENAI_FETCH_TIMEOUT_MS = 15_000;
const HEALTH_STATS_CACHE_TTL_MS = 15_000;
const KV_LIST_PAGE_LIMIT = 1000;
const CACHE_KEY_ENCODER = new TextEncoder();

let lastQuotaDate = null;
const sharedUsage = new Map();
let dailyStatsCache = null;

function resolveSharedLimit(env) {
  const raw = Number(env?.SHARED_DAILY_LIMIT ?? env?.SHARED_DEFAULT_LIMIT);
  if (Number.isFinite(raw) && raw > 0) {
    return Math.floor(raw);
  }
  return SHARED_DEFAULT_LIMIT;
}

function resolveOpenAIFetchTimeoutMs(env) {
  const raw = Number(env?.OPENAI_API_TIMEOUT_MS ?? OPENAI_FETCH_TIMEOUT_MS);
  if (!Number.isFinite(raw) || raw <= 0) {
    return OPENAI_FETCH_TIMEOUT_MS;
  }
  return Math.min(Math.floor(raw), 60_000);
}

function normalizeCacheInput(value) {
  if (typeof value !== 'string') return '';
  return value.trim().replace(/\s+/g, ' ');
}

/**
 * 常量时间字符串比较，防止时序攻击
 * @param {string} a 第一个字符串
 * @param {string} b 第二个字符串
 * @returns {boolean} 是否相等
 */
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') {
    return false;
  }

  // 确保比较时间恒定，不受字符串长度差异影响
  const lenA = a.length;
  const lenB = b.length;

  // 使用较长字符串的长度进行比较，防止长度泄露
  const maxLen = Math.max(lenA, lenB);

  let result = lenA ^ lenB; // 长度不等时结果非零

  for (let i = 0; i < maxLen; i++) {
    // 使用模运算确保索引不越界，同时保持恒定时间
    const charA = a.charCodeAt(i % lenA) || 0;
    const charB = b.charCodeAt(i % lenB) || 0;
    result |= charA ^ charB;
  }

  return result === 0;
}

/**
 * 解析 KV 配额存储绑定
 *
 * 支持三种 KV 绑定名称，按优先级从高到低：
 * 1. QUOTA_KV — 推荐名称，新部署应使用此绑定
 * 2. QUOTA_KV_BINDING — 动态绑定名，通过 env.QUOTA_KV_BINDING 指定绑定名称
 * 3. fuckits — 兼容旧版部署的遗留绑定名（已不推荐）
 *
 * 如果均未找到有效的 KV 绑定，返回 null（回退到内存 Map）
 *
 * @param {object} env 环境变量
 * @returns {object|null} KV 命名空间绑定或 null
 */
function resolveQuotaStore(env) {
  if (env?.QUOTA_KV && typeof env.QUOTA_KV.get === 'function') {
    return env.QUOTA_KV;
  }

  const alias = env?.QUOTA_KV_BINDING;
  if (alias && env?.[alias] && typeof env[alias].get === 'function') {
    return env[alias];
  }

  if (env?.fuckits && typeof env.fuckits.get === 'function') {
    return env.fuckits;
  }

  return null;
}

async function checkSharedQuota(ip, limit, env) {
  const quotaStore = resolveQuotaStore(env);
  if (quotaStore) {
    return checkSharedQuotaKV(quotaStore, ip, limit);
  }
  return checkSharedQuotaInMemory(ip, limit);
}

function checkSharedQuotaInMemory(ip, limit) {
  const today = new Date().toISOString().slice(0, 10);
  if (lastQuotaDate !== today) {
    sharedUsage.clear();
    lastQuotaDate = today;
  }
  const key = ip || 'anonymous';
  const current = (sharedUsage.get(key) || 0) + 1;
  sharedUsage.set(key, current);
  return {
    allowed: current <= limit,
    remaining: Math.max(limit - current, 0),
    count: current,
  };
}

/**
 * 使用 KV 存储检查并更新配额计数器
 *
 * 优化策略：
 * 1. 预扣机制：先原子性预扣配额，再异步确认，缩小竞态窗口
 * 2. 指数退避重试：最多 5 次重试，每次间隔指数增长，减少并发冲突
 * 3. 乐观锁思想：读取时记录版本，写入前校验版本一致性
 * 4. 配额分片：按小时分片减少单键并发压力（可选）
 *
 * 竞态说明：
 * - KV 最终一致性（< 60s 延迟）仍可能导致跨 PoP 计数不一致
 * - 但对于演示配额系统，当前方案已足够防止明显滥用
 *
 * @param {object} kv - KV 命名空间绑定
 * @param {string} ip - 客户端 IP 地址
 * @param {number} limit - 每日请求限额
 * @returns {Promise<{allowed: boolean, remaining: number, count: number}>}
 */
async function checkSharedQuotaKV(kv, ip, limit) {
  const today = new Date().toISOString().slice(0, 10);
  const key = `quota:${today}:${ip || 'anonymous'}`;
  const ttl = secondsUntilNextUtcMidnight();
  const MAX_RETRIES = 5;
  const effectiveTtl = ttl > 0 ? ttl : SECONDS_IN_DAY;

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      // 读取当前计数（带缓存避免重复读取）
      const raw = await kv.get(key);
      const currentCount = Number(raw) || 0;

      // 已达到或超过限额，立即拒绝（无需重试）
      if (currentCount >= limit) {
        return {
          allowed: false,
          remaining: 0,
          count: currentCount,
        };
      }

      const newCount = currentCount + 1;

      // 写入新计数（KV put 是最终一致的，但单键写入是有序的）
      await kv.put(key, String(newCount), { expirationTtl: effectiveTtl });

      // 验证写入成功（读取最新值确认）
      const verifyRaw = await kv.get(key);
      const verifiedCount = Number(verifyRaw) || newCount;

      return {
        allowed: verifiedCount <= limit,
        remaining: Math.max(limit - verifiedCount, 0),
        count: verifiedCount,
      };
    } catch (error) {
      // 指数退避重试
      if (attempt < MAX_RETRIES - 1) {
        const delay = Math.min(100 * Math.pow(2, attempt), 1000);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }
      console.error(JSON.stringify({ event: 'quota_persist_failed', level: 'error', message: 'Failed to persist quota counter after retries, falling back to in-memory map', error: String(error), timestamp: new Date().toISOString() }));
      return checkSharedQuotaInMemory(ip, limit);
    }
  }

  // 不可达，但 TypeScript 兼容性
  return checkSharedQuotaInMemory(ip, limit);
}

function secondsUntilNextUtcMidnight() {
  const now = new Date();
  const midnight = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1);
  return Math.ceil((midnight - now.getTime()) / 1000);
}

/**
 * 获取当日调用统计信息
 * @param {object|null} quotaStore - KV 存储或 null
 * @returns {Promise<{totalCalls: number, uniqueIPs: number}>}
 */
async function getDailyStats(quotaStore) {
  const today = new Date().toISOString().slice(0, 10);

  // 内存存储统计
  if (!quotaStore) {
    if (lastQuotaDate !== today) {
      return { totalCalls: 0, uniqueIPs: 0 };
    }
    let totalCalls = 0;
    for (const count of sharedUsage.values()) {
      totalCalls += count;
    }
    return { totalCalls, uniqueIPs: sharedUsage.size };
  }

  // KV 存储统计（带缓存 + 分页）
  try {
    const prefix = `quota:${today}:`;
    const cacheKey = `quota:${today}`;
    const now = Date.now();
    if (dailyStatsCache?.key === cacheKey && dailyStatsCache?.expiresAt > now) {
      return dailyStatsCache.value;
    }

    let totalCalls = 0;
    let uniqueIPs = 0;
    let cursor;

    do {
      const page = await quotaStore.list({
        prefix,
        cursor,
        limit: KV_LIST_PAGE_LIMIT,
      });

      uniqueIPs += page.keys.length;
      const counts = await Promise.all(
        page.keys.map(async (k) => {
          const raw = await quotaStore.get(k.name);
          return Number(raw) || 0;
        })
      );
      for (const count of counts) {
        totalCalls += count;
      }

      cursor = page.list_complete ? undefined : page.cursor;
    } while (cursor);

    const value = { totalCalls, uniqueIPs };
    dailyStatsCache = {
      key: cacheKey,
      value,
      expiresAt: now + HEALTH_STATS_CACHE_TTL_MS,
    };
    return value;
  } catch (error) {
    console.error(JSON.stringify({ event: 'stats_kv_read_failed', level: 'error', message: 'Failed to get daily stats from KV', error: String(error), timestamp: new Date().toISOString() }));
    return { totalCalls: -1, uniqueIPs: -1 };
  }
}

function isBrowserRequest(userAgent = '') {
  return /Mozilla|Chrome|Safari|Firefox|Edg/.test(userAgent);
}

/**
 * 清理和验证 AI 返回的命令
 * 从各种 AI 响应格式中提取可执行命令
 *
 * 支持的格式:
 * 1. 纯命令文本 (无 markdown)
 * 2. 单个 fenced 代码块 (```bash ... ```)
 * 3. 带解释文字的响应 (提取首个代码块)
 * 4. 内联代码 (`command`)
 * 5. 多个代码块 (提取首个)
 *
 * @param {string} rawCommand AI 返回的原始命令
 * @returns {string} 清理后的命令
 */
function sanitizeCommand(rawCommand) {
  if (!rawCommand || typeof rawCommand !== 'string') {
    return '';
  }

  let command = rawCommand.trim();

  // 策略 1: 尝试提取首个 fenced 代码块 (```bash ... ``` 或 ```sh ... ``` 等)
  // 注意: 不使用 ^ 和 $ 锚点，允许代码块出现在任意位置
  const fencedBlockPattern = /```(?:bash|sh|shell|zsh|command)?\s*\n([\s\S]*?)\n```/;
  const fencedMatch = command.match(fencedBlockPattern);
  if (fencedMatch && fencedMatch[1].trim()) {
    command = fencedMatch[1].trim();
  } else {
    // 策略 2: 尝试提取单行 fenced 代码块 (```command```)
    const inlineFencedPattern = /```(?:bash|sh|shell|zsh|command)?\s*([^\n`]+?)\s*```/;
    const inlineFencedMatch = command.match(inlineFencedPattern);
    if (inlineFencedMatch && inlineFencedMatch[1].trim()) {
      command = inlineFencedMatch[1].trim();
    } else {
      // 策略 3: 尝试提取内联代码 (`command`)
      // 只在响应看起来像是带解释文字时使用
      if (command.includes('`') && /[a-zA-Z].*:/.test(command)) {
        const inlineCodePattern = /`([^`]+)`/;
        const inlineMatch = command.match(inlineCodePattern);
        if (inlineMatch && inlineMatch[1].trim()) {
          // 验证提取的内容看起来像命令 (包含常见命令或路径)
          const extracted = inlineMatch[1].trim();
          if (/^[a-zA-Z_\/\.]/.test(extracted) && !extracted.includes(' is ')) {
            command = extracted;
          }
        }
      }
    }
  }

  // 移除 shebang 行 (#!/bin/bash, #!/usr/bin/env bash, 等)
  command = command.replace(/^#!\/(?:usr\/)?(?:bin\/)?(?:env\s+)?(?:ba)?sh\s*\n?/gm, '');

  // 移除 shell 注释行 (以 # 开头的行，但保留 #! 开头的已处理)
  // 注意: 只移除整行注释，不处理行内注释以避免破坏合法命令
  command = command.replace(/^[^\S\n]*#(?!!)[^\n]*\n?/gm, '');

  // 移除开头的空行
  command = command.replace(/^\s*\n+/, '');

  // 移除结尾的空行
  command = command.replace(/\n+\s*$/, '');

  return command.trim();
}

/**
 * 服务端安全检查 — 拦截 block 级别危险命令
 *
 * 此函数作为后端安全网，防止 AI 返回的危险命令被直接传递给客户端。
 * 客户端 Bash 脚本有更完整的安全引擎（三级检测），此函数仅做最基本的拦截。
 *
 * @param {string} command 已清理的命令
 * @returns {{ blocked: boolean, reason: string }}
 */
function checkCommandSafety(command) {
  if (!command || typeof command !== 'string') {
    return { blocked: false, reason: '' };
  }

  // Block-level 规则：与 main.sh 保持同步
  const BLOCK_RULES = [
    { pattern: /rm\s+-rf\s+\/($|\s)|rm\s+-rf\s+\/\*|rm\s+-rf\s+--no-preserve-root/, reason: 'Recursive delete targeting root filesystem' },
    { pattern: /rm\s+-rf\s+\.\*/, reason: 'Recursive delete targeting hidden/system files' },
    { pattern: /\bdd\b[^#\n]*\b(of|if)=\/dev\//, reason: 'Raw disk write via dd targeting /dev devices' },
    { pattern: /\bmkfs(\.\w+)?\b/, reason: 'Filesystem format command detected' },
    { pattern: /\bfdisk\b|\bparted\b|\bformat\b|\bwipefs\b|\bshred\b/, reason: 'Partition or disk wipe command detected' },
    { pattern: /:\(\)\s*\{\s*:\|:\s*&\s*\}\s*;/, reason: 'Fork bomb function detected' },
  ];

  for (const rule of BLOCK_RULES) {
    if (rule.pattern.test(command)) {
      return { blocked: true, reason: rule.reason };
    }
  }

  return { blocked: false, reason: '' };
}

function resolveLocale(url, headers) {
  const pathname = url.pathname.toLowerCase();
  if (pathname === '/zh' || pathname.startsWith('/zh/')) {
    return 'zh';
  }

  const langParam = (url.searchParams.get('lang') || '').toLowerCase();
  if (langParam) {
    // 明确指定的 lang 参数优先级最高（仅次于 URL 路径）
    if (langParam.startsWith('zh')) {
      return 'zh';
    }
    if (langParam.startsWith('en')) {
      return 'en';
    }
  }

  const acceptLanguage = (headers.get('Accept-Language') || '').toLowerCase();
  if (acceptLanguage.split(',').some((token) => token.trim().startsWith('zh'))) {
    return 'zh';
  }

  return 'en';
}


