export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (request.method === 'OPTIONS') {
      return addCorsHeaders(handleOptionsRequest());
    }

    if (request.method === 'GET' && url.pathname === '/health') {
      return addCorsHeaders(await handleHealthCheck(env));
    }

    if (request.method === 'GET' && url.pathname === '/robots.txt') {
      return addCorsHeaders(handleRobotsTxt());
    }

    if (request.method === 'GET' && url.pathname === '/sitemap.xml') {
      return addCorsHeaders(handleSitemap());
    }

    if (request.method === 'GET' && url.pathname.startsWith('/.well-known/')) {
      const wellKnownResponse = handleWellKnown(url.pathname);
      if (wellKnownResponse) return addCorsHeaders(wellKnownResponse);
    }

    if (request.method === 'GET') {
      return addCorsHeaders(handleGetRequest(request));
    } else if (request.method === 'POST') {
      return addCorsHeaders(await handlePostRequest(request, env, ctx));
    } else {
      return addCorsHeaders(new Response('Expected GET or POST', { status: 405 }));
    }
  },
};

// 错误码定义
const ERROR_CODES = {
  MISSING_SYSINFO: 'MISSING_SYSINFO',
  MISSING_PROMPT: 'MISSING_PROMPT',
  MISSING_API_KEY: 'MISSING_API_KEY',
  DEMO_LIMIT_EXCEEDED: 'DEMO_LIMIT_EXCEEDED',
  AI_API_ERROR: 'AI_API_ERROR',
  EMPTY_RESPONSE: 'EMPTY_RESPONSE',
  INVALID_RESPONSE: 'INVALID_RESPONSE',
  INTERNAL_ERROR: 'INTERNAL_ERROR',
  REQUEST_TOO_LARGE: 'REQUEST_TOO_LARGE',
};

// 请求体大小限制 (64KB)
const MAX_REQUEST_BODY_SIZE = 64 * 1024;

/**
 * 生成唯一请求追踪 ID
 * @returns {string} UUID v4 格式的请求 ID
 */
function generateRequestId() {
  return crypto.randomUUID();
}

/**
 * 使用 SHA-256 生成缓存 key
 * @param {string} prompt 用户提示词
 * @param {string} sysinfo 系统信息
 * @param {string} model AI 模型名称
 * @param {string} locale 语言环境 (en/zh)
 * @returns {Promise<string>} 十六进制 hash 字符串
 */
async function generateCacheKey(prompt, sysinfo, model, locale) {
  const normalizedPrompt = normalizeCacheInput(prompt);
  const normalizedSysinfo = normalizeCacheInput(sysinfo);
  const input = `${model}:${locale}:${normalizedSysinfo}:${normalizedPrompt}`;
  const data = CACHE_KEY_ENCODER.encode(input);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  return `ai:${hashHex}`;
}

/**
 * 从缓存中获取 AI 响应
 * @param {string} cacheKey 缓存键
 * @param {object} env 环境变量
 * @returns {Promise<string|null>} 缓存的命令,不存在则返回 null
 */
async function getCachedResponse(cacheKey, env) {
  if (!env.AI_CACHE) {
    return null;
  }
  try {
    const cached = await env.AI_CACHE.get(cacheKey);
    return cached;
  } catch (error) {
    console.error(JSON.stringify({ event: 'cache_read_error', level: 'error', message: 'Cache read error', error: String(error), timestamp: new Date().toISOString() }));
    return null;
  }
}

/**
 * 将 AI 响应写入缓存
 * @param {string} cacheKey 缓存键
 * @param {string} command 生成的命令
 * @param {object} env 环境变量
 * @returns {Promise<void>}
 */
async function setCachedResponse(cacheKey, command, env) {
  if (!env.AI_CACHE) {
    return;
  }
  try {
    // 缓存 24 小时 (86400 秒)
    await env.AI_CACHE.put(cacheKey, command, {
      expirationTtl: CACHE_TTL_SECONDS,
    });
  } catch (error) {
    console.error(JSON.stringify({ event: 'cache_write_error', level: 'error', message: 'Cache write error', error: String(error), timestamp: new Date().toISOString() }));
  }
}

/**
 * 获取缓存统计信息
 * @param {object} env 环境变量
 * @returns {Promise<object>} 缓存统计 {hits, misses, hitRate}
 */
async function getCacheStats(env) {
  if (!env.AI_CACHE) {
    return { enabled: false };
  }
  try {
    const today = new Date().toISOString().slice(0, 10);
    const hitsKey = `stats:hits:${today}`;
    const missesKey = `stats:misses:${today}`;

    // 并行读取 KV 以减少延迟 (Codex 优化建议)
    const [hitsValue, missesValue] = await Promise.all([
      env.AI_CACHE.get(hitsKey),
      env.AI_CACHE.get(missesKey)
    ]);
    const hits = parseInt(hitsValue || '0', 10);
    const misses = parseInt(missesValue || '0', 10);
    const total = hits + misses;
    const hitRate = total > 0 ? (hits / total * 100).toFixed(2) : '0.00';

    return {
      enabled: true,
      hits,
      misses,
      total,
      hitRate: `${hitRate}%`,
    };
  } catch (error) {
    console.error(JSON.stringify({ event: 'cache_stats_error', level: 'error', message: 'Cache stats error', error: String(error), timestamp: new Date().toISOString() }));
    return { enabled: true, error: error.message };
  }
}

// 缓存统计：内存写入 + 批量刷新到 KV
// V8 Isolate 生命周期内内存状态持久，减少 KV 读写次数和竞态窗口
const _cacheStatsBuffer = new Map();
const FLUSH_THRESHOLD = 10; // 每 10 次写入刷新一次

function incrementCacheStatsLocal(type) {
  const today = new Date().toISOString().slice(0, 10);
  const key = `stats:${type}s:${today}`;
  _cacheStatsBuffer.set(key, (_cacheStatsBuffer.get(key) || 0) + 1);

  if (_cacheStatsBuffer.get(key) >= FLUSH_THRESHOLD) {
    return true; // 标记需要刷新
  }
  return false;
}

async function flushCacheStats(env) {
  if (!env.AI_CACHE || _cacheStatsBuffer.size === 0) return;
  const entries = [..._cacheStatsBuffer.entries()];
  _cacheStatsBuffer.clear();
  await Promise.all(entries.map(async ([key, delta]) => {
    try {
      const current = parseInt(await env.AI_CACHE.get(key) || '0', 10);
      await env.AI_CACHE.put(key, String(current + delta), { expirationTtl: CACHE_STATS_TTL_SECONDS });
    } catch (e) {
      console.error(JSON.stringify({ event: 'cache_stats_flush_error', level: 'error', message: 'Cache stats flush error', error: String(e), timestamp: new Date().toISOString() }));
    }
  }));
}

async function incrementCacheStats(type, env) {
  const shouldFlush = incrementCacheStatsLocal(type);
  if (shouldFlush) await flushCacheStats(env);
}

/**
 * 生成结构化错误响应
 * @param {string} code 错误码
 * @param {string} message 错误消息
 * @param {number} status HTTP 状态码
 * @param {object} extra 额外字段
 * @param {string} [requestId] 请求追踪 ID
 * @returns {Response}
 */
function createErrorResponse(code, message, status, extra = {}, requestId = null) {
  const payload = {
    error: code,
    message,
    timestamp: new Date().toISOString(),
    ...(requestId && { requestId }),
    ...extra,
  };
  const headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store',
  };
  if (requestId) {
    headers['X-Request-ID'] = requestId;
  }
  return new Response(JSON.stringify(payload), { status, headers });
}

function handleOptionsRequest() {
  return new Response(null, {
    status: 204,
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type',
    },
  });
}

function addCorsHeaders(response) {
  const newHeaders = new Headers(response.headers);
  newHeaders.set('Access-Control-Allow-Origin', '*');
  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: newHeaders,
  });
}

/**
 * 健康检查端点处理函数
 * 返回服务状态、版本信息、依赖服务连接状态和当日调用统计
 * @param {object} env 环境变量
 * @returns {Promise<Response>} JSON 格式的健康状态响应
 */
async function handleHealthCheck(env) {
  const quotaStore = resolveQuotaStore(env);
  const [stats, cacheStats] = await Promise.all([
    getDailyStats(quotaStore),
    getCacheStats(env),
  ]);

  const payload = {
    status: 'ok',
    version: VERSION,
    buildTime: '2026-06-04T13:04:16Z',
    timestamp: new Date().toISOString(),
    services: {
      apiKey: Boolean(env?.OPENAI_API_KEY),
      adminKey: Boolean(env?.ADMIN_ACCESS_KEY),
      kvStorage: quotaStore !== null,
      aiCache: Boolean(env?.AI_CACHE),
    },
    config: {
      model: env?.OPENAI_API_MODEL || 'gpt-5-nano',
      sharedLimit: resolveSharedLimit(env),
    },
    stats: {
      totalCalls: stats.totalCalls,
      uniqueIPs: stats.uniqueIPs,
    },
    cache: cacheStats,
  };

  return new Response(JSON.stringify(payload), {
    status: 200,
    headers: { 'Content-Type': 'application/json; charset=utf-8' },
  });
}

